#!/bin/bash
set -e
ACCT="9d56f897-bd1b-4dd1-b862-8edefb544abc"
BASE="https://format.creatorcdn.com/${ACCT}/0/0/0"
DIR="/Users/jnsilva/Claude/jnsilva-site/public/images/people"
mkdir -p "$DIR"
cd "$DIR"

dl() {
  local fname="$1" uuid="$2" crop="$3" exp="$4" hmac="$5" sub="${6:-1/1}"
  local url="${BASE}/0,0,${crop}/0-0-0/${uuid}/${sub}/${fname}?fjkss=exp=${exp}~hmac=${hmac}"
  echo "Downloading ${fname}..."
  curl -sL -o "${fname}" "${url}"
}

